// Composite icon pairs (rendered side-by-side at 62% size)
const COMPOSITE_ICONS = {
  cereal_bean: ['cereal', 'soy_bean'],
  steak_bean: ['steak', 'soy_bean'],
  honey_jar: ['honey', 'jam_jar'],
};

/**
 * Get SVG string for an icon key, with size/color substituted
 * @param {string} key - Icon key (e.g., 'bread', 'sit_restaurant')
 * @param {number} [size=18] - Icon size in px
 * @param {string} [color='currentColor'] - Stroke/fill color
 * @returns {string|null} SVG string or null if not found
 */
function getIconSvg(key, size = 18, color = 'currentColor') {
  const svg = ICONS[key];
  if (!svg) return null;
  return svg.replace(/\{w\}/g, size).replace(/\{h\}/g, size).replace(/\{c\}/g, color);
}

/**
 * Check if a key is a composite icon
 */
function isComposite(key) {
  return key in COMPOSITE_ICONS;
}

/**
 * Get both SVG strings for a composite icon
 */
function getCompositeIcons(key, size = 18, color = 'currentColor') {
  const pair = COMPOSITE_ICONS[key];
  if (!pair) return null;
  const s = Math.round(size * 0.62);
  return [getIconSvg(pair[0], s, color), getIconSvg(pair[1], s, color)];
}

export { ICONS, COMPOSITE_ICONS, getIconSvg, isComposite, getCompositeIcons };
export default ICONS;
